    effective_available = max(available_time, start_time)
    slack = delivery_time - effective_available
    if slack < 0:
        slack = 0.0

    # Normalized slack (average slack per remaining operation)
    if num_neighboring_operation > 0:
        normalized_slack = slack / num_neighboring_operation
    else:
        normalized_slack = slack

