    if processing_tm > 0:
        urgency = 0.25 * (processing_time / processing_tm)
    else:
        urgency = 0.0

    # Machine congestion: utilization normalized by number of neighboring machines
    if num_neighboring_machine > 0:
        congestion = 0.35 * (utilization / num_neighboring_machine)
    else:
        congestion = 0.35 * utilization

    # Load factor: processing time ratio to available time (dynamically scaled)
    if available_time > 0:
        load_factor = 0.15 * (processing_time / available_time)
    else:
        load_factor = 0.0

    # Base weight for normalized slack
    slack_weight = 0.5

    # Adaptive adjustment: if slack is tight (small), increase urgency and congestion influence
    if normalized_slack < 1.0:
        slack_weight = 0.3
        urgency = 0.35 * (processing_time / max(processing_tm, 1e-9))
        congestion = 0.45 * (utilization / max(num_neighboring_machine, 1))

